const fs = require("fs");
const path = require("path");
const { buildEnvFile, normalizeProfile } = require("./generate-server-secrets");
const { generateRuntimeSessionKeys } = require("./generate-runtime-session-keys");
const { checkServerEnvFile } = require("./check-server-env");

const rootDir = path.join(__dirname, "..");
const defaultEnvPath = path.join(rootDir, ".secrets", "server.env");
const defaultRuntimeKeyDir = path.join(rootDir, ".secrets", "runtime-session");
const defaultKeyVersion = "runtime-session-v1";

function usage() {
  console.log("Usage:");
  console.log("  node scripts/bootstrap-production-env.js [--profile json|sqlite] [--server-env-file file] [--runtime-key-dir dir] [--key-version label] [--force]");
  console.log("");
  console.log("Creates a private server env file and runtime-session RSA keys without printing secret values.");
}

function argValue(name, fallback = "") {
  const equalsArg = process.argv.find((arg) => arg.startsWith(`${name}=`));
  if (equalsArg) return equalsArg.slice(name.length + 1);
  const index = process.argv.indexOf(name);
  return index >= 0 && process.argv[index + 1] ? process.argv[index + 1] : fallback;
}

function parseEnvLines(text) {
  const entries = new Map();
  for (const line of String(text || "").split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const separatorIndex = line.indexOf("=");
    if (separatorIndex <= 0) continue;
    entries.set(line.slice(0, separatorIndex).trim(), line.slice(separatorIndex + 1).trim());
  }
  return entries;
}

function replaceRuntimeSessionEnv(baseEnvText, runtimeEnvText) {
  const runtimeEntries = parseEnvLines(runtimeEnvText);
  const keysToReplace = new Set([
    "ZEROLAG_RUNTIME_SESSION_KEY_VERSION",
    "ZEROLAG_RUNTIME_SESSION_PROOF_ALGORITHM",
    "ZEROLAG_RUNTIME_SESSION_PRIVATE_KEY_B64",
    "ZEROLAG_RUNTIME_SESSION_PRIVATE_KEY_PEM"
  ]);
  const lines = String(baseEnvText || "")
    .split(/\r?\n/)
    .filter((line) => {
      const key = line.split("=", 1)[0].replace(/^#\s*/, "").trim();
      return !keysToReplace.has(key);
    });

  return [
    ...lines,
    "",
    "# Runtime-session RSA proof configuration",
    "# Generated by npm run server:bootstrap. Keep private.",
    `ZEROLAG_RUNTIME_SESSION_KEY_VERSION=${runtimeEntries.get("ZEROLAG_RUNTIME_SESSION_KEY_VERSION") || defaultKeyVersion}`,
    "ZEROLAG_RUNTIME_SESSION_PROOF_ALGORITHM=RSA-SHA256",
    `ZEROLAG_RUNTIME_SESSION_PRIVATE_KEY_B64=${runtimeEntries.get("ZEROLAG_RUNTIME_SESSION_PRIVATE_KEY_B64") || ""}`,
    ""
  ].join("\n");
}

function safeRelative(filePath) {
  const relative = path.relative(rootDir, path.resolve(filePath));
  if (relative && !relative.startsWith("..") && !path.isAbsolute(relative)) return relative.replace(/\\/g, "/");
  return `${path.basename(filePath)} (external)`;
}

function assertCanWrite(filePath, force) {
  if (fs.existsSync(filePath) && !force) {
    throw new Error(`Refusing to overwrite existing file: ${filePath}`);
  }
}

function bootstrapProductionEnv(input = {}) {
  const profile = normalizeProfile(input.profile || "sqlite");
  const force = input.force === true;
  const envPath = path.resolve(input.envPath || defaultEnvPath);
  const runtimeKeyDir = path.resolve(input.runtimeKeyDir || defaultRuntimeKeyDir);
  const keyVersion = input.keyVersion || defaultKeyVersion;

  assertCanWrite(envPath, force);
  const keyResult = generateRuntimeSessionKeys({
    outputDir: runtimeKeyDir,
    keyVersion,
    force
  });
  const runtimeEnvPath = path.join(runtimeKeyDir, `${keyVersion}.server.env`);
  const serverEnv = replaceRuntimeSessionEnv(buildEnvFile(profile), fs.readFileSync(runtimeEnvPath, "utf8"));

  fs.mkdirSync(path.dirname(envPath), { recursive: true });
  fs.writeFileSync(envPath, serverEnv, "utf8");

  const envCheck = checkServerEnvFile(envPath, { profile, strict: false });
  return {
    ok: envCheck.issues.length === 0,
    profile,
    envFile: safeRelative(envPath),
    runtimeKeyVersion: keyResult.keyVersion,
    runtimeKeyDir: safeRelative(runtimeKeyDir),
    runtimePublicKeySnippet: keyResult.appConfigSnippetPath,
    envIssues: envCheck.issues.length,
    envWarnings: envCheck.warnings.length,
    nextSteps: [
      "Copy the generated app-config public key snippet into assets/app-config.json runtimeSessionPublicKeyPem.",
      "Replace payment placeholders with wechat_pay or alipay and fill the provider credential keys before paid release.",
      "Set production HTTPS URLs in assets/app-config.json and assets/update.json.",
      "Run npm run server:env-check -- --profile sqlite --strict after replacing placeholders."
    ]
  };
}

function main() {
  if (process.argv.includes("--help")) {
    usage();
    return;
  }

  try {
    const result = bootstrapProductionEnv({
      profile: argValue("--profile", "sqlite"),
      envPath: argValue("--server-env-file", defaultEnvPath),
      runtimeKeyDir: argValue("--runtime-key-dir", defaultRuntimeKeyDir),
      keyVersion: argValue("--key-version", defaultKeyVersion),
      force: process.argv.includes("--force")
    });
    console.log(JSON.stringify(result, null, 2));
  } catch (error) {
    console.error(error.message);
    process.exitCode = 1;
  }
}

if (require.main === module) {
  main();
}

module.exports = {
  bootstrapProductionEnv,
  replaceRuntimeSessionEnv
};
